import { queue, task } from "@trigger.dev/sdk";

// Define a named queue with concurrency limit of 1
const criticalQueue = queue({
  id: "critical-queue-concurrency_controlled_queue__ygCHYRg",
  name: "Critical Queue",
  concurrencyLimit: 1,
});

// Create a task that uses the critical queue
export const criticalTask = task({
  id: "criticalTask-concurrency_controlled_queue__ygCHYRg",
  name: "Critical Task",
  queue: criticalQueue,
  run: async () => {
    // Simulate work by waiting for 5 seconds
    await new Promise((resolve) => setTimeout(resolve, 5000));

    return {
      message: "Critical task completed successfully",
      timestamp: new Date().toISOString(),
    };
  },
});

